package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithFirstRecordAsHeader() throws Exception {
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        CSVFormat resultFormat = baseFormat.withFirstRecordAsHeader();

        // The method returns a CSVFormat with header set and skipHeaderRecord true
        assertNotNull(resultFormat);
        assertNotSame(baseFormat, resultFormat);

        // The header should NOT be null because withHeader() sets an empty header array
        assertNotNull(resultFormat.getHeader());
        assertEquals(0, resultFormat.getHeader().length);
        // The skipHeaderRecord flag should be true
        assertTrue(resultFormat.getSkipHeaderRecord());

        // The original format should remain unchanged
        // Use reflection to access private field 'header' of baseFormat
        java.lang.reflect.Field headerField = CSVFormat.class.getDeclaredField("header");
        headerField.setAccessible(true);
        String[] baseHeader = (String[]) headerField.get(baseFormat);
        assertNull(baseHeader);
        // Use reflection to access private field 'skipHeaderRecord' of baseFormat
        java.lang.reflect.Field skipHeaderRecordField = CSVFormat.class.getDeclaredField("skipHeaderRecord");
        skipHeaderRecordField.setAccessible(true);
        boolean baseSkipHeaderRecord = skipHeaderRecordField.getBoolean(baseFormat);
        assertFalse(baseSkipHeaderRecord);
    }
}
